"use client"
import styles from "@/app/reserve/page.module.css";
import {useState} from "react";
import {OptionProps} from "@/types/Option"

// 회의실1 버튼을 눌르면
// 나머지 버튼은 비활성화
type Option = string;

export default function Location() {
    const option: Option[] = ["ROOM1", "ROOM2", "ROOM3", "ROOM4"];
    const [selected, setSelected] = useState<Option | null>(null);

    return (
        <div>
            {option.map((opt) => (
                <SelectButton
                    key={opt}
                    option={opt}
                    selected={selected === opt}
                    onSelect={() => setSelected(opt)}
                />
            ))}
        </div>
    )
}

function SelectButton({option, selected, onSelect}: OptionProps) {
    return (
        <>
            <button
                type={"button"}
                className={`${styles.button} ${selected? styles.selected: ""}`}
                onClick={onSelect}
            >
                {option}
            </button>
        </>
    )
}